_apiWrapper.default.setEnvironment(environment);
const user = _apiWrapper.default.getRootUser();
const apiUrl = _apiWrapper.default.getApiUrl();
const loginEndpoint = _apiWrapper.default.getLoginEndpoint();
const requestBody = {
  username: user.userRoot,
  password: user.passwordRoot
};
cy.log('REQUEST:');
cy.log(`URL: POST ${apiUrl}${loginEndpoint}`);
cy.log(`BODY: ${JSON.stringify(requestBody, null, 2)}`);
cy.request({
  method: 'POST',
  url: `${apiUrl}${loginEndpoint}`,
  body: requestBody,
  failOnStatusCode: false
}).then(response => {
  cy.log('RESPONSE:');
  cy.log(`Status: ${response.status}`);
  cy.log(`HEADERS: ${JSON.stringify(response.headers, null, 2)}`);
  cy.log(`BODY: ${JSON.stringify(response.body, null, 2)}`);
  expect(response.status).to.eq(200);
  expect(response.body).to.have.property('access_token');
});
